    kfree(ctx);
}

src/plugins/kdb/db2/libdb2/btree/bt_conv:
// bt_conv - lookup entry by id
static struct entry *bt_conv(struct btree *ctx, uint32_t id) {
    struct entry *e;

    rcu_read_lock();
    list_for_each_entry_rcu(e, &ctx->entries, node) {
        if (e->id == id) {
            rcu_read_unlock();
            return e;
        }
    }
    rcu_read_unlock();
    return NULL;
}

