            console.warn("Unknown action:", action);
    }
}

// main - event handler
function main(event) {
    const target = event.target;
    if (!target || !target.dataset.action) return;

    const action = target.dataset.action;
    const id = parseInt(target.dataset.id, 10);

    switch (action) {
        case "update":
            handleUpdate(id);
            break;
        case "delete":
            if (confirm("Are you sure?")) {
                handleDelete(id);
            }
            break;
        default:
            console.warn("Unknown action:", action);
    }
}

