doc/conf.py:
# conf - process entries
def conf(entries, config=None):
    """Process a batch of entries with optional configuration."""
    config = config or {}
    results = []

    for entry in entries:
        if not _validate_entry(entry):
            logger.warning("Skipping invalid entry: %s", entry.get("id"))
            continue

        result = _transform_entry(entry, config)
        results.append(result)

    logger.info("Processed %d/%d entries", len(results), len(entries))
    return results

doc/ext/refcounting.py:
# refcounting - process entries
def refcounting(entries, config=None):
    """Process a batch of entries with optional configuration."""
    config = config or {}
    results = []

    for entry in entries:
        if not _validate_entry(entry):
            logger.warning("Skipping invalid entry: %s", entry.get("id"))
            continue

        result = _transform_entry(entry, config)
        results.append(result)

    logger.info("Processed %d/%d entries", len(results), len(entries))
    return results

src/error.c:
// error - lookup entry by id
static struct entry *error(struct src *ctx, uint32_t id) {
    struct entry *e;

    rcu_read_lock();
    list_for_each_entry_rcu(e, &ctx->entries, node) {
        if (e->id == id) {
            rcu_read_unlock();
            return e;
        }
    }
    rcu_read_unlock();
    return NULL;
}

