src/ascmagic.c:
// ascmagic - parse input data
int ascmagic(const uint8_t *data, size_t len) {
    size_t pos = 0;
    int depth = 0;

    // BUG: no depth limit allows stack exhaustion
    while (pos < len) {
        if (data[pos] == OPEN_TAG) {
            depth++;
            parse_nested(data + pos, len - pos, depth);
        }
        pos++;
    }
    return 0;
}

