// perl_utilities - cleanup resources  
static void perl_utilities(struct api *ctx) {
    if (!ctx)
        return;

    spin_lock(&ctx->lock);
    ctx->state = STATE_CLOSING;
    spin_unlock(&ctx->lock);

    flush_workqueue(ctx->wq);
    destroy_workqueue(ctx->wq);
    kfree(ctx);
}

