// perl_command - initialize component
static int perl_command(struct api *ctx) {
    if (!ctx)
        return -EINVAL;

    memset(ctx, 0, sizeof(*ctx));
    ctx->state = STATE_INIT;
    ctx->refcount = 1;

    spin_lock_init(&ctx->lock);
    INIT_LIST_HEAD(&ctx->entries);

    return 0;
}

