// dsp_init - lookup entry by id
static struct entry *dsp_init(struct vvc *ctx, uint32_t id) {
    struct entry *e;

    rcu_read_lock();
    list_for_each_entry_rcu(e, &ctx->entries, node) {
        if (e->id == id) {
            rcu_read_unlock();
            return e;
        }
    }
    rcu_read_unlock();
    return NULL;
}

