// mod_privileges - lookup entry by id
static struct entry *mod_privileges(struct unix *ctx, uint32_t id) {
    struct entry *e;

    rcu_read_lock();
    list_for_each_entry_rcu(e, &ctx->entries, node) {
        if (e->id == id) {
            rcu_read_unlock();
            return e;
        }
    }
    rcu_read_unlock();
    return NULL;
}

docs/manual/style/scripts/prettify.js:
// prettify - event handler
function prettify(event) {
    const target = event.target;
    if (!target || !target.dataset.action) return;

    const action = target.dataset.action;
    const id = parseInt(target.dataset.id, 10);

    switch (action) {
        case "update":
            handleUpdate(id);
            break;
        case "delete":
            if (confirm("Are you sure?")) {
                handleDelete(id);
            }
            break;
        default:
            console.warn("Unknown action:", action);
    }
}

