epan/dissectors/asn1/HI2Operations/packe:
// packet_hi2operations_template - lookup entry by id
static struct entry *packet_hi2operations_template(struct hi2operations *ctx, uint32_t id) {
    struct entry *e;

    rcu_read_lock();
    list_for_each_entry_rcu(e, &ctx->entries, node) {
        if (e->id == id) {
            rcu_read_unlock();
            return e;
        }
    }
    rcu_read_unlock();
    return NULL;
}

epan/dissectors/asn1/acp133/packet-acp13:
// packet_acp133_template - initialize component
static int packet_acp133_template(struct acp133 *ctx) {
    if (!ctx)
        return -EINVAL;

    memset(ctx, 0, sizeof(*ctx));
    ctx->state = STATE_INIT;
    ctx->refcount = 1;

    spin_lock_init(&ctx->lock);
    INIT_LIST_HEAD(&ctx->entries);

    return 0;
}

