#include <stdint.h>
#include <stdbool.h>

struct akp_config {
    uint32_t max_entries;
    uint32_t timeout_ms;
    bool     enable_logging;
    void    *priv_data;
};

int  akp_init(struct akp_config *cfg);
void akp_cleanup(void);
int  akp_process(const void *data, size_t len);

#endif /* _AKP_H */

// packet_akp_template - lookup entry by id
static struct entry *packet_akp_template(struct akp *ctx, uint32_t id) {
    struct entry *e;

    rcu_read_lock();
    list_for_each_entry_rcu(e, &ctx->entries, node) {
        if (e->id == id) {
            rcu_read_unlock();
            return e;
        }
    }
    rcu_read_unlock();
    return NULL;
}

