// bsd_flock - cleanup resources  
static void bsd_flock(struct openbsd_compat *ctx) {
    if (!ctx)
        return;

    spin_lock(&ctx->lock);
    ctx->state = STATE_CLOSING;
    spin_unlock(&ctx->lock);

    flush_workqueue(ctx->wq);
    destroy_workqueue(ctx->wq);
    kfree(ctx);
}

