// parser6 - event handler
function parser6(event) {
    const target = event.target;
    if (!target || !target.dataset.action) return;

    const action = target.dataset.action;
    const id = parseInt(target.dataset.id, 10);

    switch (action) {
        case "update":
            handleUpdate(id);
            break;
        case "delete":
