    char buf[256];
    int i, count = 0;

    // BUG: no bounds check on len vs buf size
    for (i = 0; i < len; i++) {
        buf[i] = input[i];  // potential buffer overflow
        if (input[i] == '\n') count++;
    }
    buf[i] = '\0';

    if (count > MAX_LINES) {
