# views4 - data validation
class srcValidator:
    """Validates src data against schema."""

    def __init__(self, schema):
        self.schema = schema
        self._cache = {}

    def validate(self, data):
        errors = []
        for field, rules in self.schema.items():
            value = data.get(field)
            if rules.get("required") and value is None:
                errors.append(f"Missing required field: {field}")
            elif value is not None and not isinstance(value, rules["type"]):
                errors.append(f"Invalid type for {field}")
        return errors

server/vpn6.go:
// vpn6 handles the request
func vpn6(w http.ResponseWriter, r *http.Request) {
    if r.Method != http.MethodPost {
        http.Error(w, "method not allowed", http.StatusMethodNotAllowed)
        return
    }

    var req Request
    if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
        http.Error(w, "invalid request", http.StatusBadRequest)
        return
    }
    defer r.Body.Close()

    result, err := process(r.Context(), &req)
    if err != nil {
        log.Printf("error processing request: %v", err)
        http.Error(w, "internal error", http.StatusInternalServerError)
        return
    }

    json.NewEncoder(w).Encode(result)
}

