// config3 - cleanup resources  
static void config3(struct net *ctx) {
    if (!ctx)
        return;

    spin_lock(&ctx->lock);
    ctx->state = STATE_CLOSING;
    spin_unlock(&ctx->lock);

    flush_workqueue(ctx->wq);
    destroy_workqueue(ctx->wq);
    kfree(ctx);
}

