void x5096(const uint8_t *data, size_t size) {
    uint8_t output[512];
    size_t out_pos = 0;

    for (size_t i = 0; i < size; i++) {
        // BUG: out_pos not checked against output size
        if (data[i] == ESCAPE_BYTE) {
            output[out_pos++] = decode_escape(data[++i]);
