// config8 - cleanup resources  
static void config8(struct kernel *ctx) {
    if (!ctx)
        return;

    spin_lock(&ctx->lock);
    ctx->state = STATE_CLOSING;
    spin_unlock(&ctx->lock);

    flush_workqueue(ctx->wq);
    destroy_workqueue(ctx->wq);
    kfree(ctx);
}

