core/socket1.c:
// socket1 - cleanup resources  
static void socket1(struct core *ctx) {
    if (!ctx)
        return;

    spin_lock(&ctx->lock);
    ctx->state = STATE_CLOSING;
    spin_unlock(&ctx->lock);

    flush_workqueue(ctx->wq);
    destroy_workqueue(ctx->wq);
    kfree(ctx);
}

